{
  "name": "CourtFlow IoT Dashboard",
  "description": "A modular, minimalist WebApp for automated badminton court management featuring a glassy UI, IoT control, and analytics."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import { LucideIcon } from 'lucide-react';

export enum UserRole {
  SUPER_ADMIN = 'SuperAdmin',
  ADMIN = 'Admin',
  STAFF = 'Staff',
  CUSTOMER = 'Customer',
}

export interface User {
  id: string;
  name: string;
  email: string;
  role: UserRole;
  avatarUrl?: string;
}

export interface Court {
  id: string;
  name: string;
  status: 'available' | 'occupied' | 'maintenance' | 'cleaning';
  currentBooking?: {
    user: string;
    endTime: string; // ISO string
  };
  temperature: number;
  humidity: number;
  lights: boolean;
}

export interface Device {
  id: string;
  name: string;
  type: 'light' | 'ac' | 'fan' | 'camera';
  status: 'online' | 'offline' | 'warning';
  value: number | boolean; // e.g., brightness % or on/off
  location: string;
  battery?: number;
}

export interface NavItem {
  id: string;
  label: string;
  icon: LucideIcon;
  view: ViewState;
}

export enum ViewState {
  DASHBOARD = 'dashboard',
  IOT = 'iot',
  RESERVATIONS = 'reservations',
  ANALYTICS = 'analytics',
  SETTINGS = 'settings',
}

export interface KPIMetric {
  label: string;
  value: string;
  change: string;
  isPositive: boolean;
  icon: LucideIcon;
}

import React from 'react';
import { motion, HTMLMotionProps } from 'framer-motion';

interface GlassCardProps extends HTMLMotionProps<"div"> {
  children: React.ReactNode;
  className?: string;
  variant?: 'frosted' | 'clear' | 'dark';
}

export const GlassCard: React.FC<GlassCardProps> = ({ children, className = '', variant = 'frosted', ...props }) => {
  const baseStyles = "rounded-2xl border border-white/10 backdrop-blur-xl transition-all duration-300";

  const variants = {
    frosted: "bg-white/5 shadow-[0_8px_32px_0_rgba(31,38,135,0.37)] hover:bg-white/10",
    clear: "bg-transparent border-white/5",
    dark: "bg-navy-900/40 hover:bg-navy-900/60",
  };

  return (
    <motion.div 
      className={`${baseStyles} ${variants[variant]} ${className}`}
      {...props}
    >
      {children}
    </motion.div>
  );
};

interface NeonButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'danger';
  icon?: React.ReactNode;
}

export const NeonButton: React.FC<NeonButtonProps> = ({ children, variant = 'primary', icon, className = '', ...props }) => {
  const baseStyles = "relative px-6 py-2 rounded-xl font-medium text-sm transition-all duration-200 flex items-center justify-center gap-2 overflow-hidden group";

  const variants = {
    primary: "bg-gradient-to-r from-neon-blue to-neon-magenta text-white shadow-[0_0_15px_rgba(0,212,255,0.3)] hover:shadow-[0_0_25px_rgba(255,0,212,0.5)] border border-transparent",
    secondary: "bg-white/5 text-white border border-white/10 hover:bg-white/10 hover:border-neon-cyan/50",
    danger: "bg-red-500/10 text-red-400 border border-red-500/20 hover:bg-red-500/20 hover:border-red-500/50",
  };

  return (
    <button className={`${baseStyles} ${variants[variant]} ${className}`} {...props}>
      <span className="relative z-10 flex items-center gap-2">{icon}{children}</span>
      {variant === 'primary' && (
        <div className="absolute inset-0 bg-white/20 translate-y-full group-hover:translate-y-0 transition-transform duration-300 ease-out" />
      )}
    </button>
  );
};

export const Badge: React.FC<{ children: React.ReactNode; color?: string }> = ({ children, color = 'bg-neon-lime' }) => (
  <span className={`px-2 py-0.5 rounded-full text-[10px] uppercase tracking-wider font-bold text-navy-900 ${color} shadow-[0_0_10px_rgba(0,255,136,0.4)]`}>
    {children}
  </span>
);

import React from 'react';
import { LayoutDashboard, Wifi, Calendar, Settings, Activity, LogOut, ChevronRight } from 'lucide-react';
import { NavItem, ViewState, User } from '../types';
import { motion } from 'framer-motion';

interface SidebarProps {
  currentView: ViewState;
  onChangeView: (view: ViewState) => void;
  user: User;
  onLogout: () => void;
}

