          <div className="absolute -inset-1 bg-gradient-to-br from-neon-blue to-neon-magenta opacity-30 blur-lg rounded-lg animate-pulse" />
        </div>
        <span className="hidden lg:block text-xl font-light tracking-wide bg-clip-text text-transparent bg-gradient-to-r from-white to-white/60">
          CourtFlow
        </span>
      </div>

      <nav className="flex-1 px-4 py-8 space-y-2">
        {navItems.map((item) => {
          const isActive = currentView === item.view;
          return (
            <button
              key={item.id}
              onClick={() => onChangeView(item.view)}
              className={`w-full flex items-center gap-4 px-3 py-3 rounded-xl transition-all duration-300 group relative overflow-hidden ${
                isActive ? 'text-white' : 'text-gray-400 hover:text-white'
