              )}

              <item.icon size={20} className={`relative z-10 transition-colors ${isActive ? 'text-neon-cyan' : 'group-hover:text-neon-magenta'}`} />
              <span className="hidden lg:block relative z-10 font-light text-sm tracking-wide">{item.label}</span>

