import React, { useState } from 'react';
import { GlassCard, NeonButton } from '../components/UI';
import { Device } from '../types';
import { Lightbulb, Fan, Wind, Power, AlertTriangle, RefreshCw } from 'lucide-react';
import { motion } from 'framer-motion';

const initialDevices: Device[] = [
  { id: 'd1', name: 'Court 1 Main Light', type: 'light', status: 'online', value: 80, location: 'Court 1' },
  { id: 'd2', name: 'Court 1 AC Unit', type: 'ac', status: 'online', value: true, location: 'Court 1' },
  { id: 'd3', name: 'Court 2 Main Light', type: 'light', status: 'online', value: 0, location: 'Court 2' },
  { id: 'd4', name: 'Ventilation Fan A', type: 'fan', status: 'warning', value: true, location: 'Hallway' },
  { id: 'd5', name: 'Court 3 Main Light', type: 'light', status: 'offline', value: 0, location: 'Court 3' },
  { id: 'd6', name: 'Court 4 Main Light', type: 'light', status: 'online', value: 100, location: 'Court 4' },
];

const IoT: React.FC = () => {
  const [devices, setDevices] = useState<Device[]>(initialDevices);

  const toggleDevice = (id: string) => {
    setDevices(prev => prev.map(d => {
      if (d.id === id) {
        if (typeof d.value === 'boolean') return { ...d, value: !d.value };
        return { ...d, value: d.value > 0 ? 0 : 100 };
      }
      return d;
    }));
  };

  const handleSliderChange = (id: string, newVal: number) => {
    setDevices(prev => prev.map(d => d.id === id ? { ...d, value: newVal } : d));
  };

  const getIcon = (type: Device['type']) => {
    switch (type) {
      case 'light': return Lightbulb;
      case 'ac': return Wind;
      case 'fan': return Fan;
      default: return Power;
    }
  };

  return (
    <div className="space-y-6 pb-20">
      <div className="flex justify-between items-end">
        <div>
          <h2 className="text-2xl font-light text-white mb-1">IoT Control Center</h2>
          <p className="text-gray-400 text-sm">Manage court lighting, climate, and ventilation.</p>
        </div>
        <NeonButton variant="secondary" icon={<RefreshCw size={16} />}>Scan Devices</NeonButton>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {devices.map((device) => {
          const Icon = getIcon(device.type);
          const isOn = typeof device.value === 'boolean' ? device.value : device.value > 0;

          return (
            <GlassCard key={device.id} className="p-6 relative group overflow-hidden">
               <div className="flex justify-between items-start mb-6">
                 <div className="flex items-center gap-3">
                   <div className={`p-3 rounded-2xl transition-all duration-300 ${
                     isOn ? 'bg-neon-cyan/20 text-neon-cyan shadow-[0_0_20px_rgba(0,212,255,0.3)]' : 'bg-white/5 text-gray-500'
                   }`}>
                     <Icon size={24} />
                   </div>
                   <div>
                     <h3 className="text-white font-medium">{device.name}</h3>
                     <p className="text-xs text-gray-500">{device.location}</p>
                   </div>
                 </div>
                 <div className={`w-2 h-2 rounded-full ${
                   device.status === 'online' ? 'bg-green-500 shadow-[0_0_8px_#22c55e]' : 
                   device.status === 'warning' ? 'bg-yellow-500 animate-pulse' : 'bg-red-500'
                 }`} />
               </div>

               <div className="space-y-4">
                 {device.type === 'light' ? (
                   <div>
                     <div className="flex justify-between text-xs text-gray-400 mb-2">
                       <span>Brightness</span>
                       <span>{device.value}%</span>
                     </div>
                     <input 
                       type="range" 
                       min="0" 
                       max="100" 
                       value={device.value as number}
                       onChange={(e) => handleSliderChange(device.id, parseInt(e.target.value))}
                       className="w-full h-1.5 bg-white/10 rounded-lg appearance-none cursor-pointer accent-neon-cyan"
                     />
                   </div>
                 ) : (
                   <div className="flex items-center justify-between">
                     <span className="text-sm text-gray-400">Power Status</span>
                     <button 
                       onClick={() => toggleDevice(device.id)}
                       className={`w-12 h-6 rounded-full p-1 transition-colors duration-300 ${isOn ? 'bg-neon-cyan' : 'bg-white/10'}`}
                     >
                       <div className={`w-4 h-4 bg-white rounded-full shadow-md transform transition-transform duration-300 ${isOn ? 'translate-x-6' : 'translate-x-0'}`} />
                     </button>
                   </div>
                 )}
               </div>

               {device.status === 'warning' && (
                 <div className="mt-4 flex items-center gap-2 text-yellow-500 text-xs bg-yellow-500/10 p-2 rounded-lg border border-yellow-500/20">
                   <AlertTriangle size={14} />
                   <span>Maintenance required soon.</span>
                 </div>
               )}

                {/* Decorative Elements */}
               {isOn && (
                 <div className="absolute top-0 right-0 w-32 h-32 bg-neon-cyan/10 blur-[60px] rounded-full pointer-events-none" />
               )}
            </GlassCard>
          );
        })}
      </div>
    </div>
  );
};

export default IoT;

import React from 'react';
import { GlassCard, NeonButton } from '../components/UI';
import { Calendar as CalendarIcon, Clock, User, ChevronLeft, ChevronRight, Filter } from 'lucide-react';

const timeSlots = ['08:00', '09:00', '10:00', '11:00', '12:00', '13:00', '14:00', '15:00', '16:00', '17:00', '18:00', '19:00', '20:00'];
const courts = ['Court 1', 'Court 2', 'Court 3', 'Court 4'];

const bookings = [
  { court: 0, time: '09:00', user: 'Alice M.', duration: 2, status: 'confirmed' },
  { court: 1, time: '10:00', user: 'Bob K.', duration: 1, status: 'pending' },
  { court: 2, time: '14:00', user: 'Team A', duration: 3, status: 'confirmed' },
  { court: 3, time: '18:00', user: 'Coach T.', duration: 2, status: 'confirmed' },
];

const Reservations: React.FC = () => {
  return (
    <div className="space-y-6 pb-20 h-full flex flex-col">
      {/* Header */}
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h2 className="text-2xl font-light text-white">Reservations</h2>
          <p className="text-gray-400 text-sm">Drag to select slots or manage incoming requests.</p>
        </div>
        <div className="flex items-center gap-3">
           <div className="flex items-center bg-white/5 rounded-lg border border-white/10 p-1">
             <button className="p-2 hover:bg-white/10 rounded-md text-gray-400 hover:text-white"><ChevronLeft size={16} /></button>
             <span className="px-3 text-sm font-medium text-white">Oct 24, 2023</span>
             <button className="p-2 hover:bg-white/10 rounded-md text-gray-400 hover:text-white"><ChevronRight size={16} /></button>
           </div>
           <NeonButton variant="secondary" icon={<Filter size={16} />}>Filter</NeonButton>
           <NeonButton icon={<CalendarIcon size={16} />}>New Booking</NeonButton>
        </div>
      </div>

      {/* Calendar Grid */}
      <GlassCard className="flex-1 overflow-hidden flex flex-col min-h-[600px] !p-0">
        <div className="grid grid-cols-[80px_1fr_1fr_1fr_1fr] border-b border-white/10 bg-navy-900/50">
          <div className="p-4 text-center text-xs font-semibold text-gray-500 uppercase tracking-wider border-r border-white/5">Time</div>
          {courts.map((court) => (
            <div key={court} className="p-4 text-center text-sm font-medium text-white border-r border-white/5 last:border-r-0">
              {court}
            </div>
          ))}
        </div>

        <div className="flex-1 overflow-y-auto custom-scrollbar">
          {timeSlots.map((time, timeIndex) => (
            <div key={time} className="grid grid-cols-[80px_1fr_1fr_1fr_1fr] border-b border-white/5 hover:bg-white/[0.02] transition-colors group">
              <div className="p-3 text-center text-xs text-gray-500 border-r border-white/5 relative">
                 <span className="-translate-y-1/2 top-0 absolute right-4 block bg-navy-900 px-1">{time}</span>
              </div>

              {courts.map((_, courtIndex) => {
                const booking = bookings.find(b => b.court === courtIndex && b.time === time);

                return (
                  <div key={courtIndex} className="relative border-r border-white/5 last:border-r-0 h-16 group/cell">
                    {/* Hover Add Button */}
                    <button className="absolute inset-0 w-full h-full opacity-0 group-hover/cell:opacity-100 bg-neon-blue/5 flex items-center justify-center text-neon-blue transition-all">
                      <span className="text-xl font-light">+</span>
                    </button>

                    {booking && (
                      <div 
                        className={`absolute inset-1 rounded-lg p-2 border text-xs cursor-pointer z-10 transition-transform hover:scale-[1.02] ${
                          booking.status === 'confirmed' 
                            ? 'bg-neon-blue/20 border-neon-blue/30 text-neon-blue' 
                            : 'bg-yellow-500/20 border-yellow-500/30 text-yellow-500'
                        }`}
                        style={{ height: `calc(${booking.duration * 100}% + ${(booking.duration - 1) * 1}px - 8px)` }}
                      >
                        <div className="font-semibold flex items-center gap-1 mb-1">
                           {booking.user}
                        </div>
                        <div className="flex items-center gap-1 opacity-80">
                          <Clock size={10} />
                          <span>{booking.duration}h</span>
                        </div>
                      </div>
                    )}
                  </div>
                );
              })}
            </div>
          ))}
        </div>
      </GlassCard>
    </div>
  );
};

export default Reservations;

import React, { useState, useEffect } from 'react';
