import { motion, AnimatePresence } from 'framer-motion';
import { Bell, Search } from 'lucide-react';
import { GlassCard } from './components/UI';

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [currentView, setCurrentView] = useState<ViewState>(ViewState.DASHBOARD);
  const [isLoading, setIsLoading] = useState(true);

  // Mock User
  const user: User = {
    id: 'u1',
    name: 'Admin User',
    email: 'admin@courtflow.io',
    role: UserRole.SUPER_ADMIN,
  };

  useEffect(() => {
    // Simulate initial loading
    const timer = setTimeout(() => {
      setIsLoading(false);
    }, 1000);
    return () => clearTimeout(timer);
  }, []);

  const handleLogin = () => {
    setIsAuthenticated(true);
  };

  const handleLogout = () => {
    setIsAuthenticated(false);
    setCurrentView(ViewState.DASHBOARD);
  };

  if (isLoading) {
    return (
      <div className="h-screen w-full bg-navy-900 flex items-center justify-center">
        <div className="relative">
          <div className="w-16 h-16 border-t-2 border-r-2 border-neon-cyan rounded-full animate-spin" />
          <div className="absolute inset-0 w-16 h-16 border-b-2 border-l-2 border-neon-magenta rounded-full animate-spin reverse" style={{ animationDirection: 'reverse', animationDuration: '1.5s' }} />
        </div>
      </div>
    );
  }

  if (!isAuthenticated) {
    return <Login onLogin={handleLogin} />;
  }

  const renderContent = () => {
    switch (currentView) {
      case ViewState.DASHBOARD:
        return <Dashboard />;
      case ViewState.IOT:
        return <IoT />;
      case ViewState.RESERVATIONS:
        return <Reservations />;
      default:
        return (
          <div className="flex flex-col items-center justify-center h-[60vh] text-gray-500">
            <h3 className="text-xl font-light">Module Under Construction</h3>
            <p className="text-sm mt-2">Check back later for updates.</p>
          </div>
        );
    }
  };

  return (
    <div className="min-h-screen bg-navy-900 text-white font-sans selection:bg-neon-cyan/30">
      <Sidebar 
        currentView={currentView} 
        onChangeView={setCurrentView} 
        user={user}
        onLogout={handleLogout}
      />

      <main className="pl-20 lg:pl-64 min-h-screen transition-all duration-300">
        {/* Top Header */}
        <header className="sticky top-0 z-40 px-8 py-5 flex justify-between items-center backdrop-blur-md bg-navy-900/50 border-b border-white/5">
           <div className="flex-1 max-w-md hidden md:block">
             <div className="relative group">
               <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-500 group-focus-within:text-neon-cyan transition-colors" size={16} />
               <input 
                 type="text" 
                 placeholder="Search bookings, devices, or customers..." 
                 className="w-full bg-white/5 border border-white/10 rounded-full py-2 pl-10 pr-4 text-sm text-white placeholder-gray-500 focus:outline-none focus:border-neon-cyan/50 focus:bg-white/10 transition-all"
               />
             </div>
           </div>

           <div className="flex items-center gap-4">
             <button className="relative p-2 rounded-full hover:bg-white/5 transition-colors text-gray-400 hover:text-white">
               <Bell size={20} />
               <span className="absolute top-2 right-2.5 w-2 h-2 bg-neon-magenta rounded-full animate-pulse shadow-[0_0_8px_#ff00d4]" />
             </button>
           </div>
        </header>

        {/* Content Area */}
        <div className="p-4 md:p-8 max-w-7xl mx-auto">
          <AnimatePresence mode="wait">
            <motion.div
              key={currentView}
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              exit={{ opacity: 0, y: -20 }}
              transition={{ duration: 0.3 }}
            >
              {renderContent()}
            </motion.div>
          </AnimatePresence>
        </div>
      </main>
    </div>
  );
};

