import React, { useState } from 'react';
import { GlassCard, NeonButton } from '../components/UI';
import { Device } from '../types';
import { Lightbulb, Fan, Wind, Power, AlertTriangle, RefreshCw } from 'lucide-react';

const initialDevices: Device[] = [
  { id: 'd1', name: 'Court 1 Main Light', type: 'light', status: 'online', value: 80, location: 'Court 1' },
  { id: 'd2', name: 'Court 1 AC Unit', type: 'ac', status: 'online', value: true, location: 'Court 1' },
  { id: 'd3', name: 'Court 2 Main Light', type: 'light', status: 'online', value: 0, location: 'Court 2' },
  { id: 'd4', name: 'Ventilation Fan A', type: 'fan', status: 'warning', value: true, location: 'Hallway' },
  { id: 'd5', name: 'Court 3 Main Light', type: 'light', status: 'offline', value: 0, location: 'Court 3' },
  { id: 'd6', name: 'Court 4 Main Light', type: 'light', status: 'online', value: 100, location: 'Court 4' },
];

const IoT: React.FC = () => {
  const [devices, setDevices] = useState<Device[]>(initialDevices);

  const toggleDevice = (id: string) => {
    setDevices(prev => prev.map(d => {
      if (d.id === id) {
        if (typeof d.value === 'boolean') return { ...d, value: !d.value };
        return { ...d, value: d.value > 0 ? 0 : 100 };
      }
      return d;
    }));
  };

  const handleSliderChange = (id: string, newVal: number) => {
    setDevices(prev => prev.map(d => d.id === id ? { ...d, value: newVal } : d));
  };

  const getIcon = (type: Device['type']) => {
    switch (type) {
      case 'light': return Lightbulb;
      case 'ac': return Wind;
      case 'fan': return Fan;
      default: return Power;
    }
  };

  return (
    <div className="space-y-6 pb-20">
      <div className="flex justify-between items-end">
        <div>
          <h2 className="text-2xl font-light text-gray-900 mb-1">IoT Control Center</h2>
          <p className="text-gray-500 text-sm">Manage court lighting, climate, and ventilation.</p>
        </div>
        <NeonButton variant="secondary" icon={<RefreshCw size={16} />}>Scan Devices</NeonButton>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {devices.map((device) => {
          const Icon = getIcon(device.type);
          const isOn = typeof device.value === 'boolean' ? device.value : device.value > 0;

          return (
            <GlassCard key={device.id} className="p-6 relative group overflow-hidden border-t-4 border-t-transparent hover:border-t-brand-orange transition-all">
               <div className="flex justify-between items-start mb-6">
                 <div className="flex items-center gap-3">
                   <div className={`p-3 rounded-2xl transition-all duration-300 ${
                     isOn ? 'bg-orange-100 text-brand-orange shadow-inner' : 'bg-gray-100 text-gray-400'
                   }`}>
                     <Icon size={24} />
                   </div>
                   <div>
                     <h3 className="text-gray-900 font-medium">{device.name}</h3>
                     <p className="text-xs text-gray-500">{device.location}</p>
                   </div>
                 </div>
                 <div className={`w-2 h-2 rounded-full ${
                   device.status === 'online' ? 'bg-green-500 shadow-[0_0_8px_#22c55e]' : 
                   device.status === 'warning' ? 'bg-yellow-500 animate-pulse' : 'bg-red-500'
                 }`} />
               </div>

               <div className="space-y-4">
                 {device.type === 'light' ? (
                   <div>
                     <div className="flex justify-between text-xs text-gray-500 mb-2">
                       <span>Brightness</span>
                       <span>{device.value}%</span>
                     </div>
                     <input 
                       type="range" 
                       min="0" 
                       max="100" 
                       value={device.value as number}
                       onChange={(e) => handleSliderChange(device.id, parseInt(e.target.value))}
                       className="w-full h-1.5 bg-gray-200 rounded-lg appearance-none cursor-pointer accent-brand-orange"
                     />
                   </div>
                 ) : (
                   <div className="flex items-center justify-between">
                     <span className="text-sm text-gray-500">Power Status</span>
                     <button 
                       onClick={() => toggleDevice(device.id)}
                       className={`w-12 h-6 rounded-full p-1 transition-colors duration-300 ${isOn ? 'bg-brand-orange' : 'bg-gray-200'}`}
                     >
                       <div className={`w-4 h-4 bg-white rounded-full shadow-md transform transition-transform duration-300 ${isOn ? 'translate-x-6' : 'translate-x-0'}`} />
                     </button>
                   </div>
                 )}
               </div>

               {device.status === 'warning' && (
                 <div className="mt-4 flex items-center gap-2 text-yellow-600 text-xs bg-yellow-50 p-2 rounded-lg border border-yellow-200">
                   <AlertTriangle size={14} />
                   <span>Maintenance required soon.</span>
                 </div>
               )}
            </GlassCard>
          );
        })}
      </div>
    </div>
  );
};

export default IoT;

