      {/* Calendar Grid */}
      <GlassCard className="flex-1 overflow-hidden flex flex-col min-h-[600px] !p-0 shadow-md">
        <div className="grid grid-cols-[80px_1fr_1fr_1fr_1fr] border-b border-gray-200 bg-gray-50/50">
          <div className="p-4 text-center text-xs font-bold text-gray-400 uppercase tracking-wider border-r border-gray-100">Time</div>
          {courts.map((court) => (
            <div key={court} className="p-4 text-center text-sm font-semibold text-gray-700 border-r border-gray-100 last:border-r-0">
              {court}
            </div>
          ))}
        </div>

        <div className="flex-1 overflow-y-auto custom-scrollbar">
          {timeSlots.map((time, timeIndex) => (
            <div key={time} className="grid grid-cols-[80px_1fr_1fr_1fr_1fr] border-b border-gray-100 hover:bg-gray-50/30 transition-colors group">
              <div className="p-3 text-center text-xs text-gray-400 border-r border-gray-100 relative">
                 <span className="-translate-y-1/2 top-0 absolute right-4 block bg-white px-1 z-10">{time}</span>
              </div>

              {courts.map((_, courtIndex) => {
                const booking = bookings.find(b => b.court === courtIndex && b.time === time);

                return (
                  <div key={courtIndex} className="relative border-r border-gray-100 last:border-r-0 h-16 group/cell">
                    {/* Hover Add Button */}
                    <button className="absolute inset-0 w-full h-full opacity-0 group-hover/cell:opacity-100 bg-orange-50/50 flex items-center justify-center text-brand-orange transition-all">
                      <span className="text-xl font-light">+</span>
                    </button>

                    {booking && (
                      <div 
                        className={`absolute inset-1 rounded-lg p-2 border text-xs cursor-pointer z-10 transition-transform hover:scale-[1.02] shadow-sm ${
                          booking.status === 'confirmed' 
                            ? 'bg-orange-100 border-orange-200 text-orange-800' 
                            : 'bg-gray-100 border-gray-200 text-gray-600'
                        }`}
                        style={{ height: `calc(${booking.duration * 100}% + ${(booking.duration - 1) * 1}px - 8px)` }}
                      >
                        <div className="font-bold flex items-center gap-1 mb-1">
                           {booking.user}
                        </div>
                        <div className="flex items-center gap-1 opacity-70">
                          <Clock size={10} />
                          <span>{booking.duration}h</span>
                        </div>
                      </div>
                    )}
                  </div>
                );
              })}
            </div>
          ))}
        </div>
      </GlassCard>
    </div>
  );
};

