import React, { useState } from 'react';
import { GlassCard, NeonButton, Badge } from '../components/UI';
import { 
  Settings, Droplets, Zap, DollarSign, Calendar, TrendingUp, 
  X, CheckSquare, Square, BarChart3, Users
} from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';

// --- Types ---
type MetricType = 'revenue' | 'electricity' | 'water' | 'court_usage' | 'bookings' | 'vending';

interface ColumnConfig {
  id: number;
  monthStr: string; // Format "YYYY-MM"
  visibleMetrics: MetricType[];
}

interface MonthlyData {
  revenue: number;
  bookings: number;
  vendingSales: number;
  electricity: {
    units: number; // kWh
    rate: number;
    cost: number;
  };
  water: {
    units: number; // Cubic meters
    rate: number;
    cost: number;
  };
  courtUsage: { id: string; name: string; hours: number; capacity: number }[];
}

// --- Constants & Config ---
const ALL_METRICS: { id: MetricType; label: string; icon: any }[] = [
  { id: 'revenue', label: 'Total Revenue', icon: DollarSign },
  { id: 'bookings', label: 'Total Bookings', icon: Calendar },
  { id: 'court_usage', label: 'Court Usage Breakdown', icon: BarChart3 },
  { id: 'electricity', label: 'Electricity Fee', icon: Zap },
  { id: 'water', label: 'Water Fee', icon: Droplets },
  { id: 'vending', label: 'Vending Sales', icon: Users },
];

const DEFAULT_METRICS: MetricType[] = ['revenue', 'court_usage', 'electricity', 'water'];

// --- Mock Data Generator ---
const generateDataForMonth = (monthStr: string): MonthlyData => {
  // Create a pseudo-random seed from the month string to ensure consistent data for same month
  const seed = monthStr.split('').reduce((acc, char) => acc + char.charCodeAt(0), 0);
  const random = (min: number, max: number) => {
    const x = Math.sin(seed + min) * 10000;
    return Math.floor((x - Math.floor(x)) * (max - min) + min);
  };

  const elecUnits = random(800, 1500);
  const waterUnits = random(40, 120);

  return {
    revenue: random(120000, 180000),
    bookings: random(300, 500),
    vendingSales: random(15000, 30000),
    electricity: {
      units: elecUnits,
      rate: 4.5, // THB per unit
      cost: elecUnits * 4.5
    },
    water: {
      units: waterUnits,
      rate: 18, // THB per unit
      cost: waterUnits * 18
    },
    courtUsage: Array.from({ length: 8 }, (_, i) => ({
      id: `c-${i}`,
      name: `Court ${i + 1}`,
      hours: random(80, 200),
      capacity: 300 // Max hours in a month roughly
    }))
  };
};

const Analytics: React.FC = () => {
  // Initialize with Current Month, Last Month, 2 Months Ago
  const getMonthString = (offset: number) => {
    const d = new Date();
    d.setMonth(d.getMonth() - offset);
    return d.toISOString().slice(0, 7);
  };

  const [columns, setColumns] = useState<ColumnConfig[]>([
    { id: 1, monthStr: getMonthString(0), visibleMetrics: [...DEFAULT_METRICS] },
    { id: 2, monthStr: getMonthString(1), visibleMetrics: [...DEFAULT_METRICS] },
    { id: 3, monthStr: getMonthString(2), visibleMetrics: [...DEFAULT_METRICS] },
  ]);

  const [editingColumnId, setEditingColumnId] = useState<number | null>(null);

