const Reservations: React.FC = () => {
  // State
  const [currentDate, setCurrentDate] = useState(new Date());
  const [bookings, setBookings] = useState<Booking[]>(generateInitialBookings());

  // Modal State
  const [isModalOpen, setIsModalOpen] = useState(false);
